import React, { useState } from 'react';
import { X, Copy, CheckCircle } from 'lucide-react';

const PreviewPanel = ({ problem, onClose }) => {
  const [copied, setCopied] = useState(false);

  // Trạng thái trống khi chưa chọn bài nào
  if (!problem) {
    return (
      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#94a3b8', backgroundColor: '#fff', borderBottom: '1px solid #e2e8f0' }}>
        <p>👈 Chọn một bài tập ở danh sách bên trái để xem chi tiết</p>
      </div>
    );
  }

  // Hàm copy nhanh mã LaTeX
  const copyToClipboard = () => {
    const text = `\\begin{bt}\n${problem.statement}\n${problem.solution ? `\\loigiai{\n${problem.solution}\n}\n` : ''}\\end{bt}`;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000); // Tắt hiệu ứng copy sau 2 giây
  };

  return (
    <div style={{ flex: 1, display: 'flex', flexDirection: 'column', backgroundColor: '#fff', borderBottom: '1px solid #e2e8f0', overflow: 'hidden' }}>
      
      {/* Tiêu đề Khung xem trước */}
      <div style={{ padding: '1rem 1.5rem', borderBottom: '1px solid #e2e8f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center', backgroundColor: '#f8fafc' }}>
        <h3 style={{ margin: 0, fontSize: '1rem', color: '#0f172a' }}>Chi tiết câu hỏi</h3>
        <div style={{ display: 'flex', gap: '0.5rem' }}>
          <button onClick={copyToClipboard} title="Copy mã LaTeX" style={{ background: 'none', border: 'none', cursor: 'pointer', color: copied ? '#10b981' : '#64748b' }}>
            {copied ? <CheckCircle size={20} /> : <Copy size={20} />}
          </button>
          <button onClick={onClose} title="Đóng" style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#ef4444' }}>
            <X size={20} />
          </button>
        </div>
      </div>

      {/* Nội dung chi tiết */}
      <div style={{ padding: '1.5rem', overflowY: 'auto', flex: 1 }}>
        <div style={{ marginBottom: '1.5rem' }}>
          <strong style={{ color: '#3b82f6', display: 'block', marginBottom: '0.5rem' }}>Đề bài:</strong>
          <div style={{ backgroundColor: '#f1f5f9', padding: '1rem', borderRadius: '8px', whiteSpace: 'pre-wrap', fontFamily: 'monospace', fontSize: '14px', color: '#334155' }}>
            {problem.statement}
          </div>
        </div>

        {problem.solution && (
          <div>
            <strong style={{ color: '#10b981', display: 'block', marginBottom: '0.5rem' }}>Lời giải:</strong>
            <div style={{ backgroundColor: '#f0fdf4', padding: '1rem', borderRadius: '8px', whiteSpace: 'pre-wrap', fontFamily: 'monospace', fontSize: '14px', color: '#166534' }}>
              {problem.solution}
            </div>
          </div>
        )}
      </div>

    </div>
  );
};

export default PreviewPanel;
